val ARTICLE_TASSAWOF = Article(
    id = "tassawof",
    title = "التصوف",
    body = listOf(
        "لطالما كان التصوف موضع سؤال عند الناس: ما حقيقته؟ وما سرّ تعلّق جماعات به؟ وما معنى الذكر والأوراد؟ ولماذا تُقام المواسم على محبة الصالحين؟ وبين غياب البيان وتراكم الجهل، تعددت الاتهامات وساد التشويه، حتى نُسب للتصوف ما ليس منه، ونُزعت عنه شمائله التي عرفها السلف من قبل.",
        "والحق أن التصوف كما هو عند أهله الصادقين ليس طقوسًا ولا خروجًا عن الشريعة، بل هو قلب الشريعة المحمدية وروحها، وهو مقام الإحسان في أكمل تجلياته.",
        "مراتب الدين: بيّن النبي صلى الله عليه وسلم أن الدين على ثلاث درجات. أولها الإسلام، وهو الاستسلام لله ظاهرًا بأداء الشهادة والصلاة والزكاة والصيام والحج. وثانيها الإيمان، وهو تصديق القلب وطمأنينته بالغيب، وهو مرتبة أعلى من الإسلام. وثالثها الإحسان، وهو لبّ الدين وروحه: «أن تعبد الله كأنك تراه»، وهو مقام لا يُنال إلا بتزكية النفس وكثرة الذكر وصدق المحبة.",
        "فالتصوف إذن هو السعي للوصول إلى مقام الإحسان، بتهذيب الباطن وإحكام الظاهر على نور من الكتاب والسنة. هو تزكية النفس التي أمر الله بها، وإحياء القلب بذكر الله، والصدق في طلب وجه الله. هو الإسلام إذا صفا، والإيمان إذا رقّ، والإحسان إذا أصبح حالًا دائمًا؛ حرقة في القلب لا خرقة تُلبس ظاهرًا. وليس التصوف مذهبًا جديدًا ولا دينًا موازيًا للدين، بل هو تربية روحية وأخلاقية تكمل بناء المسلم.",
        "مرتكزات التصوف الشرعي خمسة: الالتزام بالكتاب والسنة (فكل ما خالفهما فباطل مهما نُسب لأهل الطريق)، وتزكية النفس ومجاهدتها، والإكثار من الذكر والطاعة (فبالذكر يحيا القلب وتصفو الروح)، وصحبة الصالحين (فالمرء يرقى بصحبة أهل الأدب والورع)، والتحلي بالأخلاق النبوية من الصدق والرحمة والتواضع والصفح ولين الجانب.",
        "وليس من التصوف: الخرافات والشعوذة، وادعاء الكشف بلا علم، وترك الفرائض، والغلوّ في الأشخاص، والبدع المحدثة التي لا أصل لها. فالتصوف الحق يزيدك التزامًا بالشريعة لا خروجًا عنها.",
        "التصوف في كلمات: هو الجانب الروحي من الإسلام، وأدب مع الله وأدب مع الخلق، وطريق يمرّ بالنفس ليصل إلى القلب، ومن القلب إلى ربّ القلب. طرقه تختلف، لكن هدفه واحد: قرب من الله جل وعلا، وسلام في القلب. والصوفي لا يطلب الكرامة ولا الشهرة والجاه، بل يطلب رضا الكريم؛ فإذا رأيته قلتَ في نفسك: هذا رجل ذكّرني بالله.",
        "خلاصة: التصوف هو الإسلام حين يُعاش بقلب محب، والإيمان حين يتزين بالنور، والإحسان حين يثبت في السلوك. هو الشريعة حين تُثمر حقيقة، والعبادة حين تتحول إلى شهود، ومحبة الله حين تصير حياة. ومن ذاق عرف، ومن عرف صفا، ومن صفا وفى.",
    ),
    source = "بتصرف عن: www.cheikhiyya.com — تعريف التصوف، بحث وتحقيق مقدم الطريقة الشيخية حاكمي مصطفى",
)

val ARTICLE_TARIQA_CHEIKHIYYA = Article(
    id = "tariqa_cheikhiyya",
    title = "الطريقة الشيخية",
    body = listOf(
        "قال الإمام أحمد الرفاعي رضي الله عنه: الطريقة هي الشريعة، والشريعة هي الطريقة، والفرق بينهما لفظي، أما المادة والمعنى والنتيجة فواحدة. وقال الإمام الشعراني: إن طريق القوم محررة على الكتاب والسنة كتحرير الذهب والجوهر، فيحتاج سالكها إلى ميزان شرعي في كل حركة وسكون. وقال الإمام الجنيد البغدادي: الطرق كلها مسدودة على الخلق إلا من اقتفى أثر الرسول صلى الله عليه وسلم واتبع سنته ولزم طريقته، فإن طرق الخيرات كلها مفتوحة عليه.",
        "فالطريقة الشيخية من تأسيس قطب زمانه، إمام الصوفية الجامع بين الشريعة والحقيقة، الولي الصالح المجاهد الشهيد سيدي عبد القادر بن محمد السماحي المعروف بسيدي الشيخ رضي الله عنه. وهي طريقة إسلامية سنية صوفية، تحث على طاعة الله والالتزام بالسنة المطهرة، جامعة بين الشريعة والحقيقة، شيخية المشرب شاذلية المرجع محمدية الأصل والمنبع، بسندها المتصل إلى الإمام أبي الحسن الشاذلي رضي الله عنه، ثم منه إلى سيد الوجود سيدنا محمد صلى الله عليه وسلم.",
        "يقوم مبنى الطريقة على طلب العلم، واحترام العلماء والفقهاء والشرفاء والفقراء، وكثرة ذكر الله مع الحضور، وهي من أقوم وأبسط وأقرب الطرق إلى الله، متمسكة بآداب الشريعة التي تحث على فضيلة الوسط دون غلو في المجاهدة أو الجوع أو السهر، سليمة من كدورات جهلة المتصوفة.",
        "قال مؤسس الطريقة في الياقوتة: «وحال لها حوى الأصول بأسرها طريقة أسلاف بيضاء نقية، فهذي فصولها وشرط كمالها منوط بعلم ثم حلم وحكمة». وقال تلميذه العلامة القاضي سيدي محمد عبد الله الجراري في مدحها: «طريقي إلى الرحمان حاوي المذاهب وحائز قصب السبق أعلى المراتب، تسمى بعبد القادر بن محمد لديه يروم المرء كل المواهب».",
        "يعتنق الطريقة الشيخية عدد كبير من المريدين لا يعلم عددهم إلا الله، بالمغرب العربي والشرق الأوسط وآسيا وأوروبا وأمريكا، وخاصة حيث ينتشر أولاد سيدي الشيخ والقبائل التابعة لها: كالشرفاء، والبوبكرية، والمهاية، والعكارمة، وحميان، والعمور، وأولاد جرير، وبني مطهر، وبني كيل، والرزاينة، والقرارشة، والشعانبة، وأولاد عزيز، ولعنانات، والبهاليل، وذوي منيع الأغواط، والبرابر، والزكارة، وانكاد، وغيرهم من القبائل المخلصة والوفية للطريقة.",
        "مهمة الطريقة الشيخية: تحفيظ كتاب الله، وتعليم أصول الدين وعلومه على ضوء العقيدة الأشعرية والفقه المالكي والتصوف السني المغاربي الأصيل، والدعوة إلى الله، والمحافظة على الطهارة وصلاة الجماعة، وذكر الله مع الفقراء، والنصح لكل مسلم، ومحاربة البدع والانحرافات والشعوذة بالحكمة والموعظة الحسنة.",
    ),
    source = "بتصرف عن: www.cheikhiyya.com — تعريف الطريقة الشيخية البوشيخية، بحث وتحقيق مقدم الطريقة حاكمي مصطفى",
)

val ARTICLE_BAYA = Article(
    id = "baya_adab",
    title = "العهد والبيعة وآداب الذكر",
    body = listOf(
        "كيفية العهد والبيعة: يغتسل المريد أولًا بنية تجديد التوبة، ويصلي ركعتين نفلًا يسأل الله فيهما التوبة والقبول، وأنه رضي بالشيخ سيدي عبد القادر بن محمد شيخًا له وبطريقته سبيلًا للتربية والسلوك إلى الله.",
        "ثم يتصافح المريد مع الشيخ أو نائبه (المقدم)، فيخلو به لِيُعلِمه صورة الطريق وما يترتب عليها، وينصحه بطاعة الله والالتزام بالسنة وفعل الخيرات وترك المنكرات، والدوام على الطهارة وصلاة الجماعة وذكر الله ومخالطة الصالحين والانقطاع عن أصحاب السوء، وإرضاء الخصوم وإصلاح ما أفسد وكفّ الأذى والتصبر عليه. ويُعلَم المريد أن ورد الطريقة لا تُضاف عليه أوراد أخرى إلا بإذن الشيخ الحالي أو خلفائه.",
        "ثم يضع الشيخ أو خليفته يده اليمنى فوق رأس المريد، إشارة إلى أنه شريك في التوبة، ويغض عينيه ويسكت قليلًا لتجتمع همته، ثم يستغفر الله ثلاثًا ويصلي على النبي صلى الله عليه وسلم، ويتبعه المريد في ذلك، ثم يدعو له بخير الدنيا والآخرة. أما تلقين النساء فلا يكون إلا بإذن أزواجهن.",
        "آداب الذكر: على المريد أن يكون على وضوء، محافظًا على صلاة الجماعة. وعند الذكر يستقبل القبلة، ولا يشغل باله بأمور الدنيا، ويُعلّق قلبه بالله ذليلًا خاشعًا مطيعًا، واضعًا شيخه بين عينيه، نظيف الفم طيب الرائحة، يجلس على شقّه الأيمن لا مربّعًا، ولا يشرب الماء أثناء الذكر، وإذا ناداه أحد أثناء الورد قال: سبحان الله.",
    ),
    source = "بتصرف عن: www.cheikhiyya.com — تعريف الطريقة الشيخية البوشيخية",
)

val ARTICLE_TARIQA_CONDITIONS = Article(
    id = "tariqa_conditions",
    title = "شروط الانتساب إلى الطريقة",
    body = listOf(
        "تنقسم شروط الانتساب إلى الطريقة الشيخية الشاذلية إلى قسمين: شروط صحة لا بد منها، وشروط كمال على من يستطيعها.",
        "أولًا: شروط الصحة التي لا بد منها (11 شرطًا): الاغتسال بنية تجديد التوبة، والتلفظ بالشهادتين بنية الوجوب، وصلاة ركعتي التوبة بالكافرون والإخلاص، والقول بحضرة المقدم أو الشيخ (أعوذ بالله من الشيطان الرجيم، بسم الله الرحمن الرحيم، أستغفر الله العظيم مرتين وأتوب إليه، اللهم تب علينا ووفقنا لما تحبه وترضاه، وصل اللهم على سيدنا محمد وعلى آله والحمد لله رب العالمين)، وإحضار نية التوبة من جميع الذنوب مع العزم على عدم العودة إليها، وأداء حقوق الخصوم ومصالحتهم مع سلامة الصدر لجميع المسلمين، والمحافظة على الفرائض واجتناب المحرمات، والمحافظة على حزب الفلاح بعد صلاتي الصبح والمغرب، والمحافظة على الأذكار السرية بعد الصبح والعشاء دون كلام أثناءها، واحترام وطاعة مقدم الطريقة في المعروف، وتحري الحلال في المطعم والملبس والمركب والمسكن.",
        "ثانيًا: شروط الكمال على من يستطيعها (14 شرطًا): الصلاة في المسجد مع الجماعة، وختم القرآن الكريم كل شهر قمري، والمحافظة على الرواتب والنوافل والسنن، والتفقه في الدين عامة وأركان الإسلام خاصة، وقيام الليل ولو بركعتين مع الدعاء قبل أذان الصبح، ومحاسبة النفس قبل النوم، وصيام الاثنين والخميس والأيام البيض وغيرها من الأيام الفاضلة، وإحياء سنة النبي صلى الله عليه وسلم في اللباس والطعام والنوم والمعاشرة، والتقليل من الطعام والنوم، واستقبال القبلة والطهارة وجلسة التواضع وتغميض العينين أثناء الذكر الخاص، وكثرة الذكر مع تكراره بعد الظهر والعصر والمغرب، وحضور مجالس الذكر مع إكرام الذاكرين في بيته، وزيارة الشيخ والمقدم والصالحين أحياء وأمواتًا، ومطالعة كتب القوم وسيرهم.",
    ),
    source = "بتصرف عن: www.cheikhiyya.com — شروط المريد البوشيخي (تعريف الطريقة الشيخية البوشيخية)",
)

val ARTICLE_SIDI_HAMZA = Article(
    id = "sidi_hamza",
    title = "الشيخ الحالي للطريقة الشيخية: سيدي حمزة",
    body = listOf(
        "هو العارف بالله والدال عليه، الولي الصالح سيدي أبو محمد حمزة بن عبد الحاكم بن الطيب بن أبي عمامة البوشيخي الصديقي. وُلد مطلع رجب 1344هـ الموافق لأوائل يناير 1926م بجبل غينا، بين قيادتي المريجة وتكافايت (إقليم جرادة، المغرب)، لأمه السيدة الفاضلة العابدة فاطنة بنت إبراهيم الملقبة بالصحراوية من آل سيدي الحاج أحمد البوشيخي. وفي تلك السنة ارتحلت الزاوية إلى مقرها الأخير قرب عين بني مطهر بنفس الإقليم.",
        "تعلم القرآن ومبادئ الفقه واللغة العربية في الزاوية على يد فقهائها السجلماسيين، وتعلم الفرنسية في مدرسة بمدينة مغنية قرب الحدود المغربية الجزائرية. وفي سنة 1946م رحل إلى فرنسا وبلجيكا، حيث قضى قرابة أربع سنوات أتقن فيها اللغتين واستفاد من ثقافة أوروبا وفنونها، ثم عاد سنة 1950م إلى الزاوية لمعاونة والده الشيخ في تسييرها.",
        "انخرط سنة 1952م مناضلًا في حزب الاستقلال، مشاركًا في المقاومة الوطنية ضد الاستعمار الفرنسي. وبعد نفي الملك محمد الخامس سنة 1953م، هاجر مستخفيًا إلى الدار البيضاء خوفًا من الاعتقال، إذ قُبض على كثير من أفراد عائلته المنخرطين في الحزب، فعمل في القاعدة الجوية الأمريكية بالنواصر وفي «جنان الغاتر» قرب الحدود المغربية الجزائرية.",
        "بعد استقلال المغرب، رجع إلى فرنسا واشتغل بأعمال حرة (تعليم السياقة، بيع اللحوم الحلال)، ثم عاد نهائيًا إلى الزاوية سنة 1962م لتمريض والده الذي طال به المرض قرابة أربع سنوات، حتى توفي سنة 1966م فآلت إليه مشيخة الزاوية. كان قد شغل منصب رئيس المجلس القروي لعين بني مطهر منذ 1963م، ثم دخل البرلمان سنة 1970م، واستمر رئيسًا للمجلس القروي والبلدي إلى سنة 1992م، وعضوًا في المجلس الإقليمي لولاية وجدة لسنوات. وحصل على وسام الرضى من الملك الحسن الثاني رحمه الله لتفوق بلديته ولعمله في تلك الوظائف دون مقابل مادي.",
        "منذ سنة 1992م اعتزل السياسة نهائيًا وتفرغ للعبادة وشؤون الزاوية: استقبال الوفود والمريدين وتعليمهم وتوجيههم، وإلقاء الدروس والمواعظ بمسجد الزاوية العتيق الذي وسّعه مرتين، وتشييد المدرسة القرآنية. ودليل انتهاء مشيخة الطريقة إليه أن الياقوتة الحجرية للشيخ المؤسس سيدي عبد القادر بن محمد، رمز المشيخة، في حيازته، إضافة إلى طوابع وخواتم مؤسس الطريقة وغيره من أعلامها.",
        "عمل جاهدًا على إعطاء شعلة جديدة للطريقة، خصوصًا بين الشباب، فعيّن مجموعة من المقدمين الشباب المثقفين في ديار المهجر كفرنسا وإسبانيا وإيطاليا، وامتدت الطريقة في عهده إلى الشرق الأوسط، إضافة إلى الجزائر حيث العدد الأكبر من الأتباع. وأقام سنة 2005م الموسم الأول لسيدي عبد القادر بن محمد بالزاوية البوعمامية، وكان موسمًا مثاليًا بشهادة الجميع.",
        "أبناؤه الذكور سبعة: محمد، والعربي، وعتيق، وبلحرمة، والطيب، وعبد الحاكم، والشيخ؛ وابنتاه ربيعة وخديجة، كلهم من زوجته الوحيدة الزهرة بنت الحاج أبوحفص، شيخ زاوية الموحدين بالرقاصة (ولاية البيض، الجزائر). يتجند أبناؤه السبعة اليوم إلى جانبه، كل في مجاله، لخدمة زوار الزاوية ومريديها.",
        "وإذا كان الشيخ بوعمامة مجدد الطريقة ومجاهدها، والشيخ الطيب محببها ومنورها، والشيخ عبد الحاكم ناشرها وموسعها، فإن الشيخ حمزة هو ممولها ومقوي اقتصادها، حتى صارت الزاوية في وقته مستغنية بالله ثم به عما في أيدي الناس. لا يستنكف عن العمل في حقول الزاوية مع المستخدمين، أول الناس دخولًا إلى المسجد وآخرهم خروجًا منه، خاصة في صلاة الصبح.",
        "نظرًا لتدهور حالته الصحية، عهد بمشيخة الطريقة بوصية شفوية وعدلية إلى نجله البار سيدي الدكتور الحاج بلحرمة، ليواصل المسيرة نسأل الله له التوفيق.",
    ),
    source = "بتصرف عن: www.cheikhiyya.com — ترجمة الشيخ الحالي للطريقة الشيخية الشاذلية سيدي حمزة، بحث وتحقيق خادم الطريقة حاكمي مصطفى",
)

val ARTICLE_SIDI_ABDELKADER = Article(
    id = "sidi_abdelkader",
    title = "سيدي عبد القادر بن محمد (سيدي الشيخ) — المؤسس",
    body = listOf(
